from ortools.sat.python import cp_model

def solve(jobs: list[list[dict]]) -> list[list[dict]]:
    model = cp_model.CpModel()

    # Extract the number of jobs and machines
    num_jobs = len(jobs)
    num_machines = max(max(op["machine"] for op in job) for job in jobs) + 1

    # Create dictionaries to store interval variables and start variables
    intervals = {}
    starts = {}
    ends = {}

    # Create interval variables for each operation
    for job_idx, job in enumerate(jobs):
        for op_idx, op in enumerate(job):
            machine = op["machine"]
            duration = op["duration"]
            suffix = f"_{job_idx}_{machine}_{op_idx}"
            start = model.NewIntVar(0, 10000, f"start{suffix}")
            end = model.NewIntVar(0, 10000, f"end{suffix}")
            interval = model.NewIntervalVar(start, duration, end, f"interval{suffix}")
            intervals[(job_idx, op_idx)] = interval
            starts[(job_idx, op_idx)] = start
            ends[(job_idx, op_idx)] = end

    # Add precedence constraints within each job
    for job_idx, job in enumerate(jobs):
        for op_idx in range(len(job) - 1):
            current_interval = intervals[(job_idx, op_idx)]
            next_interval = intervals[(job_idx, op_idx + 1)]
            model.Add(current_interval.EndExpr() <= next_interval.StartExpr())

    # Add no-overlap constraints for each machine
    for machine in range(num_machines):
        machine_intervals = [
            intervals[(job_idx, op_idx)]
            for job_idx, job in enumerate(jobs)
            for op_idx, op in enumerate(job)
            if op["machine"] == machine
        ]
        model.AddNoOverlap(machine_intervals)

    # Minimize makespan (maximum end time)
    makespan = model.NewIntVar(0, 10000, "makespan")
    model.AddMaxEquality(makespan, [ends[(job_idx, op_idx)] for job_idx, job in enumerate(jobs) for op_idx in range(len(job))])
    model.Minimize(makespan)

    # Solve the model
    solver = cp_model.CpSolver()
    status = solver.Solve(model)

    # Extract the solution
    if status == cp_model.OPTIMAL or status == cp_model.FEASIBLE:
        result = []
        for job_idx, job in enumerate(jobs):
            job_result = []
            for op_idx, op in enumerate(job):
                start_time = solver.Value(starts[(job_idx, op_idx)])
                job_result.append({
                    "machine": op["machine"],
                    "duration": op["duration"],
                    "start": start_time
                })
            result.append(job_result)
        return result
    else:
        raise ValueError("No feasible solution found.")

from ortools.sat.python import cp_model
import random

def solve(jobs: list[list[dict]]) -> list[list[dict]]:
    # Greedy initial solution: schedule operations as early as possible
    def greedy_schedule(jobs):
        num_jobs = len(jobs)
        num_machines = max(op['machine'] for job in jobs for op in job) + 1
        machine_availability = [0] * num_machines
        job_availability = [0] * num_jobs
        scheduled_jobs = []

        for job_idx, job in enumerate(jobs):
            scheduled_ops = []
            for op in job:
                machine = op['machine']
                duration = op['duration']
                start = max(job_availability[job_idx], machine_availability[machine])
                scheduled_ops.append({
                    "machine": machine,
                    "duration": duration,
                    "start": start
                })
                job_availability[job_idx] = start + duration
                machine_availability[machine] = start + duration
            scheduled_jobs.append(scheduled_ops)
        return scheduled_jobs

    # CP-SAT sub-solver for repair
    def cp_sat_solver(jobs, time_limit=1):
        model = cp_model.CpModel()
        num_jobs = len(jobs)
        num_machines = max(op['machine'] for job in jobs for op in job) + 1
        all_ops = [op for job in jobs for op in job]
        horizon = sum(op['duration'] for op in all_ops)

        # Variables
        starts = {}
        for job_idx, job in enumerate(jobs):
            for op_idx, op in enumerate(job):
                starts[(job_idx, op_idx)] = model.NewIntVar(0, horizon, f'start_{job_idx}_{op_idx}')

        # Constraints
        # 1. Operation order within a job
        for job_idx, job in enumerate(jobs):
            for op_idx in range(1, len(job)):
                prev_op = job[op_idx - 1]
                curr_op = job[op_idx]
                model.Add(starts[(job_idx, op_idx)] >= starts[(job_idx, op_idx - 1)] + prev_op['duration'])

        # 2. Machine capacity (no overlap)
        for machine in range(num_machines):
            ops_on_machine = [(job_idx, op_idx) for job_idx, job in enumerate(jobs) for op_idx, op in enumerate(job) if op['machine'] == machine]
            intervals = []
            for job_idx, op_idx in ops_on_machine:
                duration = jobs[job_idx][op_idx]['duration']
                start = starts[(job_idx, op_idx)]
                end = start + duration
                interval = model.NewIntervalVar(start, duration, end, f'interval_{job_idx}_{op_idx}')
                intervals.append(interval)
            model.AddNoOverlap(intervals)

        # Objective: minimize makespan
        makespan = model.NewIntVar(0, horizon, 'makespan')
        for job_idx, job in enumerate(jobs):
            last_op_idx = len(job) - 1
            model.Add(makespan >= starts[(job_idx, last_op_idx)] + job[last_op_idx]['duration'])
        model.Minimize(makespan)

        # Solve
        solver = cp_model.CpSolver()
        solver.parameters.max_time_in_seconds = time_limit
        status = solver.Solve(model)

        # Extract solution
        if status == cp_model.OPTIMAL or status == cp_model.FEASIBLE:
            scheduled_jobs = []
            for job_idx, job in enumerate(jobs):
                scheduled_ops = []
                for op_idx, op in enumerate(job):
                    scheduled_ops.append({
                        "machine": op['machine'],
                        "duration": op['duration'],
                        "start": solver.Value(starts[(job_idx, op_idx)])
                    })
                scheduled_jobs.append(scheduled_ops)
            return scheduled_jobs
        else:
            return None

    # LNS: iteratively destroy and repair
    def lns(jobs, max_iterations=100):
        current_solution = greedy_schedule(jobs)
        current_makespan = max(op['start'] + op['duration'] for job in current_solution for op in job)

        for _ in range(max_iterations):
            # Destroy: remove operations for 2-3 machines or 2-3 jobs
            num_jobs = len(jobs)
            num_machines = max(op['machine'] for job in jobs for op in job) + 1
            destroy_type = random.choice(['machines', 'jobs'])
            if destroy_type == 'machines':
                machines_to_remove = random.sample(range(num_machines), min(2, num_machines))
                remaining_jobs = []
                for job in jobs:
                    remaining_ops = [op for op in job if op['machine'] not in machines_to_remove]
                    if remaining_ops:
                        remaining_jobs.append(remaining_ops)
            else:
                jobs_to_remove = random.sample(range(num_jobs), min(2, num_jobs))
                remaining_jobs = [job for idx, job in enumerate(jobs) if idx not in jobs_to_remove]

            # Repair: solve the sub-problem with CP-SAT
            repaired_jobs = cp_sat_solver(remaining_jobs, time_limit=1)
            if repaired_jobs is None:
                continue

            # Reconstruct full solution
            new_solution = []
            if destroy_type == 'machines':
                for job_idx, job in enumerate(jobs):
                    new_ops = []
                    for op in job:
                        if op['machine'] in machines_to_remove:
                            # Re-insert removed operations (greedily)
                            machine = op['machine']
                            duration = op['duration']
                            start = max(new_ops[-1]['start'] + new_ops[-1]['duration'] if new_ops else 0,
                                        max((rep_op['start'] + rep_op['duration']) for rep_job in repaired_jobs for rep_op in rep_job if rep_op['machine'] == machine))
                            new_ops.append({
                                "machine": machine,
                                "duration": duration,
                                "start": start
                            })
                        else:
                            # Use repaired operations
                            for rep_job in repaired_jobs:
                                for rep_op in rep_job:
                                    if rep_op['machine'] == op['machine'] and rep_op['duration'] == op['duration']:
                                        new_ops.append(rep_op)
                                        break
                    new_solution.append(new_ops)
            else:
                for job_idx, job in enumerate(jobs):
                    if job_idx in jobs_to_remove:
                        # Re-insert removed jobs (greedily)
                        new_ops = []
                        start = 0
                        for op in job:
                            machine = op['machine']
                            duration = op['duration']
                            start = max(start, max((rep_op['start'] + rep_op['duration']) for rep_job in repaired_jobs for rep_op in rep_job if rep_op['machine'] == machine))
                            new_ops.append({
                                "machine": machine,
                                "duration": duration,
                                "start": start
                            })
                            start += duration
                        new_solution.append(new_ops)
                    else:
                        # Use repaired jobs
                        for rep_job in repaired_jobs:
                            if rep_job[0]['machine'] == job[0]['machine'] and rep_job[0]['duration'] == job[0]['duration']:
                                new_solution.append(rep_job)
                                break

            # Update if improved
            new_makespan = max(op['start'] + op['duration'] for job in new_solution for op in job)
            if new_makespan < current_makespan:
                current_solution = new_solution
                current_makespan = new_makespan

        return current_solution

    return lns(jobs)

import random
from collections import deque

def solve(jobs: list[list[dict]]) -> list[list[dict]]:
    def build_graph(jobs, machine_order):
        nodes = []
        edges = []
        job_count = len(jobs)
        machine_count = len(machine_order)

        for job_idx in range(job_count):
            for op_idx in range(len(jobs[job_idx])):
                nodes.append((job_idx, op_idx))

        for job_idx in range(job_count):
            for op_idx in range(len(jobs[job_idx]) - 1):
                edges.append(((job_idx, op_idx), (job_idx, op_idx + 1), jobs[job_idx][op_idx]['duration']))

        for machine in range(machine_count):
            ops_on_machine = []
            for job_idx in range(job_count):
                for op_idx in range(len(jobs[job_idx])):
                    if jobs[job_idx][op_idx]['machine'] == machine:
                        ops_on_machine.append((job_idx, op_idx))

            sorted_ops = sorted(ops_on_machine, key=lambda x: machine_order[machine].index(x))
            for i in range(len(sorted_ops) - 1):
                edges.append((sorted_ops[i], sorted_ops[i + 1], jobs[sorted_ops[i][0]][sorted_ops[i][1]]['duration']))

        return nodes, edges

    def longest_path(nodes, edges):
        distance = {node: 0 for node in nodes}
        in_degree = {node: 0 for node in nodes}
        graph = {node: [] for node in nodes}

        for u, v, weight in edges:
            graph[u].append((v, weight))
            in_degree[v] += 1

        queue = deque([node for node in nodes if in_degree[node] == 0])
        topo_order = []

        while queue:
            u = queue.popleft()
            topo_order.append(u)
            for v, weight in graph[u]:
                if distance[v] < distance[u] + weight:
                    distance[v] = distance[u] + weight
                in_degree[v] -= 1
                if in_degree[v] == 0:
                    queue.append(v)

        return distance

    def calculate_makespan(jobs, machine_order):
        nodes, edges = build_graph(jobs, machine_order)
        distance = longest_path(nodes, edges)
        makespan = max(distance.values())
        return makespan

    def get_machine_order(jobs):
        machine_count = max(op['machine'] for job in jobs for op in job) + 1
        machine_order = []
        for machine in range(machine_count):
            ops_on_machine = []
            for job_idx in range(len(jobs)):
                for op_idx in range(len(jobs[job_idx])):
                    if jobs[job_idx][op_idx]['machine'] == machine:
                        ops_on_machine.append((job_idx, op_idx))
            machine_order.append(ops_on_machine)
        return machine_order

    def generate_neighbor(machine_order):
        neighbor = [ops.copy() for ops in machine_order]
        machine = random.randint(0, len(machine_order) - 1)
        if len(neighbor[machine]) > 1:
            i, j = random.sample(range(len(neighbor[machine])), 2)
            neighbor[machine][i], neighbor[machine][j] = neighbor[machine][j], neighbor[machine][i]
        return neighbor

    def schedule_from_machine_order(jobs, machine_order):
        scheduled_jobs = []
        for job in jobs:
            scheduled_jobs.append([op.copy() for op in job])

        for job in scheduled_jobs:
            for op in job:
                op['start'] = 0

        for machine in range(len(machine_order)):
            current_time = 0
            for job_idx, op_idx in machine_order[machine]:
                duration = scheduled_jobs[job_idx][op_idx]['duration']
                if op_idx > 0:
                    prev_op = scheduled_jobs[job_idx][op_idx - 1]
                    current_time = max(current_time, prev_op['start'] + prev_op['duration'])
                scheduled_jobs[job_idx][op_idx]['start'] = current_time
                current_time += duration

        return scheduled_jobs

    machine_order = get_machine_order(jobs)
    current_makespan = calculate_makespan(jobs, machine_order)
    best_makespan = current_makespan
    best_machine_order = machine_order

    max_iterations = 1000
    for _ in range(max_iterations):
        neighbor = generate_neighbor(machine_order)
        neighbor_makespan = calculate_makespan(jobs, neighbor)
        if neighbor_makespan < current_makespan:
            current_makespan = neighbor_makespan
            machine_order = neighbor
            if current_makespan < best_makespan:
                best_makespan = current_makespan
                best_machine_order = machine_order
        else:
            if random.random() < 0.1:
                machine_order = neighbor

    final_schedule = schedule_from_machine_order(jobs, best_machine_order)
    return final_schedule
